// src/pages/Historial.jsx
import { useState, useEffect } from 'react'
import { obtenerDocumentos } from '../lib/documentos.js'
import { ROLES_FIRMA, FLUJO, verificarPin, firmarDocumento } from '../lib/firmas.js'
import { getSession } from '../lib/auth.js'

const TIPO_LABEL = { plan: 'Plan de Trabajo', informe: 'Informe Diario' }
const TIPO_COLOR = { plan: '#0D2B45', informe: '#15803d' }
const C = { navy:'#0D2B45', gold:'#C9A84C', green:'#15803d', red:'#dc2626', gray:'#64748b', border:'#e2e8f0' }
const LOGO_JPEG_B64 = ''

// ── generarCodigo ──────────────────────────────────────────────
function generarCodigo(docId, rolKey, timestamp) {
  const base = (docId + rolKey + (timestamp || '')).toUpperCase().replace(/[^A-Z0-9]/g, '')
  const p1 = base.slice(0, 4).padEnd(4, 'X')
  const p2 = base.slice(4, 8).padEnd(4, 'X')
  const p3 = (docId || '').slice(-6).toUpperCase().padStart(6, '0')
  const p4 = (timestamp || '').replace(/\D/g, '').slice(-8).padStart(8, '0')
  return `${p1}${p2}-${p3}-${p4}`
}

// ── Bloque HTML de firma (para PDF) ───────────────────────────
function bloqueHtmlFirma(firma, rolLabel, docId, rolKey) {
  if (!firma?.firmado) return ''
  const codigo = generarCodigo(docId, rolKey, firma.timestamp)
  return `
<div style="border:1px solid #e2e8f0;border-radius:10px;overflow:hidden;margin-bottom:12px;font-family:Arial,sans-serif;">
  <div style="background:#0D2B45;padding:12px 18px;display:flex;justify-content:space-between;align-items:center;">
    <div>
      <div style="font-size:13px;font-weight:700;color:#fff;margin-bottom:1px;">${rolLabel}</div>
      <div style="font-size:10px;color:#C9A84C;font-weight:600;text-transform:uppercase;letter-spacing:2px;">Firma Electronica</div>
    </div>
    <div style="background:#dcfce7;color:#15803d;border-radius:4px;padding:4px 12px;font-size:11px;font-weight:700;">&#10003; FIRMADO</div>
  </div>
  <div style="padding:14px 18px;background:#fff;">
    <div style="display:flex;gap:10px;margin-bottom:12px;">
      <div style="flex:3;background:#f8fafc;border:1px solid #f1f5f9;border-radius:8px;padding:12px 14px;">
        <div style="font-size:9px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">Firmante</div>
        <div style="font-size:15px;font-weight:700;color:#0D2B45;margin-bottom:2px;">${firma.nombre}</div>
        ${firma.cargo   ? `<div style="font-size:12px;color:#475569;">${firma.cargo}</div>` : ''}
      </div>
      <div style="flex:2;background:#f8fafc;border:1px solid #f1f5f9;border-radius:8px;padding:12px 14px;">
        <div style="font-size:9px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">Fecha y Hora</div>
        <div style="font-size:15px;font-weight:700;color:#0D2B45;margin-bottom:2px;">${firma.fecha}</div>
        <div style="font-size:12px;color:#475569;">${firma.hora} hrs CLT</div>
      </div>
    </div>
    <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:10px 14px;">
      <div style="font-size:9px;font-weight:700;color:#15803d;text-transform:uppercase;letter-spacing:1px;margin-bottom:5px;">Codigo de Verificacion</div>
      <div style="font-family:monospace;font-size:12px;color:#0D2B45;background:#fff;border:1px solid #d1fae5;border-radius:5px;padding:7px 12px;margin-bottom:4px;">SHA-256: ${codigo}</div>
      <div style="font-size:10px;color:#16a34a;font-style:italic;">Este codigo garantiza la autenticidad del documento</div>
    </div>
  </div>
  <div style="border-top:1px solid #f1f5f9;padding:7px 18px;display:flex;justify-content:space-between;background:#fafafa;">
    <span style="font-size:9.5px;color:#64748b;">Certificado por <strong style="color:#0D2B45;">MPF Ingenieria Civil SpA</strong></span>
    <span style="font-size:9.5px;color:#94a3b8;">Ley N&deg; 19.799</span>
  </div>
</div>`
}

// ── HTML del PDF ───────────────────────────────────────────────
function generarHTML(doc, logoJpegB64) {
  const firmas = doc.firmas || {}

  const contenidoHTML = (doc.contenido || '').split('\n').map(line => {
    if (line.startsWith('## ')) return `<h2 style="font-size:12px;font-weight:700;color:#0D2B45;margin:14px 0 6px;padding:5px 10px 5px 12px;border-left:3px solid #C9A84C;background:#f8f9fb;">${line.slice(3)}</h2>`
    if (line.startsWith('# '))  return `<h1 style="font-size:14px;font-weight:700;color:#0D2B45;margin:16px 0 6px;">${line.slice(2)}</h1>`
    if (line.startsWith('- '))  return `<div style="padding:2px 0 2px 12px;font-size:12px;color:#334155;line-height:1.6;"><span style="color:#C9A84C;margin-right:5px;">&#8226;</span>${line.slice(2)}</div>`
    if (/^-{3,}$/.test(line.trim())) return ''
    if (!line.trim()) return '<div style="height:5px;"></div>'
    return `<p style="margin:3px 0;font-size:12px;color:#334155;line-height:1.65;">${line.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')}</p>`
  }).join('\n')

  const fichaItems = [
    doc.sector                  ? ['Sector / Plataforma', doc.sector] : null,
    (doc.nombre||doc.usuario)   ? ['Realizado por', doc.nombre||doc.usuario] : null,
    doc.fecha                   ? ['Fecha', doc.fecha] : null,
    doc.extraFields?.supervisor ? ['Supervisor', doc.extraFields.supervisor] : null,
    doc.extraFields?.horaIn     ? ['Hora inicio', doc.extraFields.horaIn] : null,
    doc.extraFields?.horaFin    ? ['Hora termino', doc.extraFields.horaFin] : null,
  ].filter(Boolean)

  const fichaHTML = fichaItems.length ? `<div style="display:flex;flex-wrap:wrap;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden;margin-bottom:18px;">${fichaItems.map(([l,v]) => `<div style="flex:1;min-width:110px;padding:9px 13px;border-right:1px solid #e2e8f0;background:#f8fafc;"><div style="font-size:8.5px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">${l}</div><div style="font-size:12.5px;font-weight:700;color:#0D2B45;">${v}</div></div>`).join('')}</div>` : ''

  const rawLayout = (doc.layoutPngB64 || '').trim()
  const hasLayout = rawLayout.length > 200
  const layoutSrc = hasLayout ? (rawLayout.startsWith('data:') ? rawLayout : `data:image/png;base64,${rawLayout}`) : ''
  const layoutHTML = hasLayout ? `<div style="margin:16px 0;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden;"><div style="background:#0D2B45;padding:7px 13px;font-size:9px;font-weight:700;color:#C9A84C;text-transform:uppercase;letter-spacing:2px;">Layout Referencial</div><div style="padding:10px;background:#fff;text-align:center;"><img src="${layoutSrc}" style="max-width:100%;height:auto;display:block;margin:0 auto;border-radius:4px;" /></div></div>` : ''

  const bloquesFirmas = FLUJO.map(k => bloqueHtmlFirma(firmas[k], ROLES_FIRMA[k]?.label||k, doc.id, k)).join('')
  const titulo = (doc.titulo||'Documento MPF').replace(/\s*[–\-]\s*\d{4}-\d{2}-\d{2}$/, '')

  const CSS = `* { box-sizing:border-box; margin:0; padding:0; }
html,body { font-family:Arial,Helvetica,sans-serif; background:#fff; color:#1e293b; font-size:13px; }
@page { size:A4; margin:0; }
@media print { * { -webkit-print-color-adjust:exact !important; print-color-adjust:exact !important; } }`

  return `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><style>${CSS}</style></head>
<body style="width:210mm;">
<div style="background:#0D2B45;display:flex;align-items:stretch;min-height:84px;">
  <div style="background:#C9A84C;width:5px;flex-shrink:0;"></div>
  <div style="background:#fff;padding:10px 14px;display:flex;align-items:center;justify-content:center;border-right:3px solid #C9A84C;flex-shrink:0;width:128px;">
    <canvas id="lc" width="200" height="104"></canvas>
  </div>
  <div style="padding:12px 18px;flex:1;display:flex;flex-direction:column;justify-content:center;overflow:hidden;">
    <div style="font-size:8.5px;font-weight:700;color:#C9A84C;text-transform:uppercase;letter-spacing:2px;margin-bottom:5px;">MPF Ingenieria Civil SpA &middot; Proyecto Rio Tinto Mining</div>
    <div style="font-size:17px;font-weight:700;color:#fff;line-height:1.25;margin-bottom:3px;">${titulo}</div>
    <div style="font-size:10px;color:rgba(255,255,255,0.5);">${TIPO_LABEL[doc.tipo]||doc.tipo} &middot; ${doc.fecha||''} &middot; ${doc.sector||''}</div>
  </div>
  <div style="padding:12px 16px;display:flex;align-items:center;flex-shrink:0;">
    <div style="background:rgba(255,255,255,0.12);border:1px solid rgba(255,255,255,0.25);color:#fff;border-radius:6px;padding:5px 13px;font-size:11px;font-weight:700;">${TIPO_LABEL[doc.tipo]||doc.tipo}</div>
  </div>
</div>
<div style="height:3px;background:linear-gradient(90deg,#C9A84C 0%,#e8d590 50%,#C9A84C 100%);"></div>
<div style="padding:18px 22px 50px;">
  ${fichaHTML}
  <div style="margin-bottom:22px;">${contenidoHTML}</div>
  ${layoutHTML}
  <div style="border-top:2px solid #e2e8f0;padding-top:18px;margin-top:8px;">
    <div style="font-size:9px;font-weight:700;color:#0D2B45;text-transform:uppercase;letter-spacing:2px;margin-bottom:12px;">Firmas y Validaciones</div>
    ${bloquesFirmas || '<div style="padding:14px;text-align:center;color:#94a3b8;font-size:12px;border:1px dashed #e2e8f0;border-radius:8px;">Sin firmas registradas</div>'}
  </div>
</div>
<div style="position:fixed;bottom:0;left:0;right:0;height:26px;border-top:2px solid #C9A84C;background:#fff;padding:0 22px;display:flex;justify-content:space-between;align-items:center;">
  <span style="font-size:8.5px;color:#94a3b8;">MPF Ingenieria Civil SpA &middot; Proyecto Rio Tinto Mining</span>
  <span style="font-size:8.5px;color:#94a3b8;">Documento de uso interno &middot; Confidencial</span>
</div>
<script>
(function(){
  var c=document.getElementById('lc'); if(!c) return;
  var ctx=c.getContext('2d',{willReadFrequently:true}); var img=new Image();
  img.onload=function(){
    ctx.drawImage(img,0,0,c.width,c.height);
    var d=ctx.getImageData(0,0,c.width,c.height); var px=d.data;
    for(var i=0;i<px.length;i+=4){
      var lum=0.299*px[i]+0.587*px[i+1]+0.114*px[i+2];
      if(lum<25) px[i+3]=0; else if(lum<55) px[i+3]=Math.round((lum-25)/30*255);
    }
    ctx.putImageData(d,0,0);
  };
  img.src='data:image/jpeg;base64,${logoJpegB64}';
})();
</script>
</body></html>`
}

// ── Modal firma ────────────────────────────────────────────────
function ModalFirma({ docId, rolKey, session, rolLabel, onFirmado, onClose }) {
  const [pin, setPin]         = useState('')
  const [error, setError]     = useState('')
  const [loading, setLoading] = useState(false)

  async function handleFirmar() {
    setError('')
    if (!pin) return setError('Ingresa tu PIN')
    setLoading(true)
    try {
      const ok = await verificarPin(session.usuario, pin)
      if (!ok) { setError('PIN incorrecto'); setLoading(false); return }
      const firma = await firmarDocumento(docId, rolKey, session.usuario, session.nombre, session.cargo || '')
      onFirmado(rolKey, firma)
    } catch(e) { setError(e.message) }
    setLoading(false)
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.6)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000 }}>
      <div style={{ background:'#fff', borderRadius:16, padding:'2rem', width:360, boxShadow:'0 24px 64px rgba(0,0,0,0.3)' }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:20 }}>
          <div>
            <div style={{ fontSize:16, fontWeight:700, color:C.navy }}>Firmar documento</div>
            <div style={{ fontSize:12, color:C.gray, marginTop:2 }}>{rolLabel}</div>
          </div>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:22, cursor:'pointer', color:C.gray }}>×</button>
        </div>
        <div style={{ background:'#f8fafc', border:`1px solid ${C.border}`, borderRadius:10, padding:'12px 14px', marginBottom:18 }}>
          <div style={{ fontSize:10, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', marginBottom:8 }}>Datos del firmante</div>
          <div style={{ display:'flex', flexDirection:'column', gap:4, fontSize:13 }}>
            <div><span style={{ color:C.gray }}>Nombre: </span><strong style={{ color:C.navy }}>{session.nombre}</strong></div>
            {session.cargo && <div><span style={{ color:C.gray }}>Cargo: </span><span style={{ color:C.navy }}>{session.cargo}</span></div>}
            {session.rut   && <div><span style={{ color:C.gray }}>RUT: </span><span style={{ color:C.navy }}>{session.rut}</span></div>}
          </div>
        </div>
        <label style={{ fontSize:11, fontWeight:700, color:C.gray, textTransform:'uppercase', letterSpacing:'.06em', display:'block', marginBottom:6 }}>PIN de firma</label>
        <input
          type="password" inputMode="numeric" maxLength={8} autoFocus
          value={pin} onChange={e => { setPin(e.target.value.replace(/\D/g,'')); setError('') }}
          placeholder="••••"
          style={{ width:'100%', padding:'12px', fontSize:26, letterSpacing:10, border:`1.5px solid ${error ? C.red : C.border}`, borderRadius:8, boxSizing:'border-box', outline:'none', textAlign:'center' }}
        />
        {error && <div style={{ marginTop:8, padding:'8px 12px', background:'#fef2f2', borderRadius:8, fontSize:13, color:C.red }}>{error}</div>}
        <button onClick={handleFirmar} disabled={loading} style={{ width:'100%', marginTop:14, padding:'12px', fontSize:14, fontWeight:700, background:loading?'#94a3b8':C.navy, color:'#fff', border:'none', borderRadius:10, cursor:loading?'not-allowed':'pointer' }}>
          {loading ? 'Procesando...' : 'Firmar documento'}
        </button>
      </div>
    </div>
  )
}

// ── Fila de firmas ─────────────────────────────────────────────
function FirmasRow({ doc, onFirmado }) {
  const session = getSession()
  const [modal, setModal] = useState(null)

  function puedeFirmar(rolKey) {
    if (doc.firmas?.[rolKey]?.firmado) return false
    if (!session) return false
    if (!ROLES_FIRMA[rolKey]?.roles.includes(session.rol)) return false
    const idx = FLUJO.indexOf(rolKey)
    return !(idx > 0 && !doc.firmas?.[FLUJO[idx-1]]?.firmado)
  }

  return (
    <>
      <div style={{ display:'flex', gap:6, flexWrap:'wrap', marginTop:8 }}>
        {FLUJO.map(rolKey => {
          const rol    = ROLES_FIRMA[rolKey]
          const firma  = doc.firmas?.[rolKey]
          const firmado = firma?.firmado
          const idx    = FLUJO.indexOf(rolKey)
          const locked = idx > 0 && !doc.firmas?.[FLUJO[idx-1]]?.firmado
          return (
            <div key={rolKey} style={{ display:'flex', alignItems:'flex-start', gap:6, padding:'7px 10px', borderRadius:8, fontSize:11, minWidth:140, background:firmado?'#f0fdf4':locked?'#fafafa':'#fff', border:`1px solid ${firmado?'#bbf7d0':C.border}`, opacity:locked?0.6:1 }}>
              <span style={{ marginTop:1, fontSize:13, color:firmado?C.green:'#cbd5e0', fontWeight:700 }}>{firmado?'✓':'○'}</span>
              <div>
                <div style={{ fontWeight:600, color:firmado?C.green:C.gray }}>{rol?.label}</div>
                {firmado ? (
                  <>
                    <div style={{ fontSize:10, color:'#475569' }}>{firma.nombre}{firma.cargo?` · ${firma.cargo}`:''}</div>
                    <div style={{ fontSize:10, color:'#94a3b8' }}>{firma.fecha} {firma.hora}</div>
                  </>
                ) : <div style={{ fontSize:10, color:'#cbd5e0' }}>{locked?'Esperando anterior':'Pendiente'}</div>}
                {puedeFirmar(rolKey) && (
                  <button onClick={() => setModal(rolKey)} style={{ marginTop:5, padding:'3px 10px', fontSize:11, fontWeight:700, background:C.navy, color:'#fff', border:'none', borderRadius:6, cursor:'pointer' }}>Firmar</button>
                )}
              </div>
            </div>
          )
        })}
      </div>
      {modal && session && (
        <ModalFirma docId={doc.id} rolKey={modal} session={session} rolLabel={ROLES_FIRMA[modal]?.label}
          onFirmado={(rk,f) => { setModal(null); onFirmado(doc.id,rk,f) }} onClose={() => setModal(null)} />
      )}
    </>
  )
}

// ── Página principal ───────────────────────────────────────────
export default function Historial() {
  const session = getSession()
  const [docs,      setDocs]      = useState([])
  const [loading,   setLoading]   = useState(true)
  const [error,     setError]     = useState('')
  const [exporting, setExporting] = useState(null)

  useEffect(() => { cargar() }, [])

  async function cargar() {
    setLoading(true); setError('')
    try {
      const data = await Promise.race([
        obtenerDocumentos(session?.empresaId, 60),
        new Promise((_,r) => setTimeout(() => r(new Error('Timeout')), 10000)),
      ])
      setDocs(data)
    } catch(e) { setError('No se pudo cargar: ' + e.message) }
    setLoading(false)
  }

  function formatFecha(ts) {
    if (!ts) return '–'
    try { const d=ts.toDate?ts.toDate():new Date(ts); return d.toLocaleDateString('es-CL',{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}) }
    catch { return '–' }
  }

  function firmasCount(f) { return f ? FLUJO.filter(k => f[k]?.firmado).length : 0 }
  function firmasColor(n) {
    const total = FLUJO.length
    if (n === total) return { bg:'#dcfce7', color:C.green, border:'#bbf7d0' }
    if (n > 0)       return { bg:'#fef9c3', color:'#92400e', border:'#fde68a' }
    return { bg:'#f1f5f9', color:C.gray, border:C.border }
  }

  function handleFirmado(docId, rolKey, firma) {
    setDocs(prev => prev.map(d => d.id!==docId ? d : { ...d, firmas:{...(d.firmas||{}),[rolKey]:firma} }))
  }

  async function descargarPDF(doc) {
    setExporting(doc.id)
    try {
      const html = generarHTML(doc, LOGO_JPEG_B64)
      const win  = window.open('','_blank','width=960,height=800,menubar=no,toolbar=no')
      if (!win) { alert('Activa ventanas emergentes para generar el PDF'); setExporting(null); return }
      win.document.write(html)
      win.document.close()
      await new Promise(r => setTimeout(r, 2000))
      win.focus(); win.print()
      win.onafterprint = () => win.close()
    } catch(e) { alert('Error: ' + e.message) }
    setExporting(null)
  }

  const total = FLUJO.length

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'1.5rem' }}>
        <div>
          <h1 style={{ fontSize:22, fontWeight:600, marginBottom:4 }}>Historial de Documentos</h1>
          <p style={{ color:C.gray, fontSize:14 }}>{loading?'Cargando...':`${docs.length} documento${docs.length!==1?'s':''}`}</p>
        </div>
        <button onClick={cargar} disabled={loading} style={{ padding:'7px 14px', fontSize:13, background:'transparent', border:`1px solid ${C.border}`, borderRadius:8, cursor:'pointer', color:'#475569' }}>
          {loading?'…':'↺ Actualizar'}
        </button>
      </div>

      {error && <div style={{ background:'#fef2f2', border:'1px solid #fecaca', borderRadius:8, padding:'12px 16px', color:C.red, fontSize:14, marginBottom:16 }}>
        ⚠️ {error} <button onClick={cargar} style={{ marginLeft:10, fontSize:13, color:C.navy, background:'none', border:'none', cursor:'pointer', textDecoration:'underline' }}>Reintentar</button>
      </div>}

      {loading ? <div style={{ textAlign:'center', padding:'3rem', color:'#94a3b8', fontSize:14 }}>Cargando historial...</div>
      : docs.length===0 ? <div style={{ textAlign:'center', padding:'3rem', color:'#94a3b8', background:'#fff', border:`1px solid ${C.border}`, borderRadius:12 }}>
          <div style={{ fontSize:15, fontWeight:500 }}>Sin documentos aún</div>
          <div style={{ fontSize:13, marginTop:6 }}>Genera documentos desde Plan de Trabajo o Informe Diario.</div>
        </div>
      : <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
          {docs.map(doc => {
            const count    = firmasCount(doc.firmas)
            const fcolor   = firmasColor(count)
            const isExp    = exporting===doc.id
            const completo = count===total
            return (
              <div key={doc.id} style={{ background:'#fff', border:`1px solid ${C.border}`, borderRadius:12, padding:'1rem 1.25rem' }}>
                <div style={{ display:'flex', alignItems:'flex-start', gap:12 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:6, flexWrap:'wrap' }}>
                      <span style={{ padding:'2px 10px', borderRadius:99, fontSize:11, fontWeight:700, background:TIPO_COLOR[doc.tipo]||C.gray, color:'#fff' }}>{TIPO_LABEL[doc.tipo]||doc.tipo}</span>
                      <span style={{ fontSize:12, color:'#94a3b8' }}>{formatFecha(doc.creadoEn)}</span>
                      <span style={{ fontSize:12, color:'#94a3b8' }}>· {doc.nombre||doc.usuario}</span>
                    </div>
                    <div style={{ fontSize:15, fontWeight:600, color:'#1e293b', marginBottom:8, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{doc.titulo}</div>
                    <FirmasRow doc={doc} onFirmado={handleFirmado} />
                  </div>
                  <div style={{ display:'flex', flexDirection:'column', alignItems:'flex-end', gap:8, flexShrink:0 }}>
                    <span style={{ padding:'4px 12px', borderRadius:99, fontSize:12, fontWeight:700, background:fcolor.bg, color:fcolor.color, border:`1px solid ${fcolor.border}` }}>
                      {completo?'✓ Listo':`${count}/${total} firmas`}
                    </span>
                    <button onClick={() => descargarPDF(doc)} disabled={isExp} style={{ padding:'7px 16px', fontSize:12, fontWeight:600, background:isExp?'#94a3b8':completo?C.green:C.navy, color:'#fff', border:'none', borderRadius:8, cursor:isExp?'not-allowed':'pointer', whiteSpace:'nowrap' }}>
                      {isExp?'Generando...':completo?'⬇ Descargar PDF':'⬇ Borrador PDF'}
                    </button>
                  </div>
                </div>
              </div>
            )
          })}
        </div>}
    </div>
  )
}
